text:
{
  "formal_minutes": {
    "meeting_meta": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": [
        "Minjun",
        "Seoyeon",
        "Doyun",
        "Hara"
      ]
    },
    "confirmed_decisions": [
      {
        "topic": "public_release_target",
        "decision": "스모크 테스트가 통과할 경우 공개 릴리스 목표 시각은 금요일 15:00 KST이다.",
        "condition": "smoke passes",
        "certainty": "confirmed"
      },
      {
        "topic": "packageName_mismatch_handling",
        "decision": "packageName mismatch가 발생하면 먼저 package config를 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토로 넘어간다.",
        "certainty": "confirmed"
      }
    ],
    "rejected_proposals": [
      {
        "topic": "ignore_packageName_mismatch",
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하자",
        "result": "rejected",
        "certainty": "confirmed"
      }
    ],
    "internal_stretch_goals": [
      {
        "topic": "wednesday_release",
        "detail": "수요일 릴리스 제안은 내부 스트레치 골로만 남았고 최종 공개 릴리스 결정은 아니다.",
        "certainty": "confirmed"
      }
    ],
    "non_decisions": [
      {
        "topic": "README_install_steps_review",
        "detail": "README 설치 절차는 가능하면 목요일까지 검토하자는 의견이 있었으나 담당자는 지정되지 않았다.",
        "certainty": "confirmed"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로로 인해 릴리스가 지연될 수 있다.",
        "certainty": "confirmed"
      },
      {
        "risk": "README 설치 절차가 오래되었으면 릴리스 노트가 사용자를 오도할 수 있다.",
        "certainty": "confirmed"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자가 누구인가?",
        "status": "open"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 골을 언급해야 하는가?",
        "status": "open"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed_pending",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed_pending",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로를 확인한다.",
      "due": "not specified",
      "status": "confirmed_pending",
      "source_certainty": "confirmed"
    },
    {
      "owner": "unassigned",
      "task": "README 설치 절차를 가능하면 목요일까지 검토한다.",
      "due": "목요일(가능하면)",
      "status": "proposed_unassigned",
      "source_certainty": "mentioned_without_owner"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 스모크 테스트 결과 통과 여부를 확인한다.",
      "스모크 결과 이후 Hara의 tarball 경로 점검 결과를 확인한다.",
      "Doyun의 failure triage note 작성 완료 여부를 확인한다.",
      "최종 릴리스 승인 권한자를 명확히 한다.",
      "README 설치 절차 검토의 담당자 지정 여부와 실제 검토 상태를 확인한다.",
      "릴리스 노트에 내부 수요일 스트레치 골을 언급할지 결정한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구",
      "지정되지 않은 담당자",
      "명시되지 않은 마감일"
    ]
  },
  "non_invention_rules": [
    "인라인 공개용 합성 픽스처에 없는 고객, 예산, 보안, 장애, 법무 사실을 추가하지 않는다.",
    "확정 결정과 기각된 제안, 내부 스트레치 골, 리스크, 미해결 질문을 혼합하지 않는다.",
    "담당자나 마감이 명시되지 않은 항목은 임의로 확정하지 않는다.",
    "수요일 릴리스는 공개 릴리스 확정안이 아니라 내부 스트레치 골로만 기록한다.",
    "Hara의 작업에는 정확한 마감이 없으므로 임의 시각을 넣지 않는다."
  ]
}
